// Parse Layer A — Semantic Scholar responses.
// Read each Scholar node by name so parsing is independent of merge mode.
const watchlist = $('Fetch Watchlist').first().json.watchlist;
const nodeNames = [
  'Scholar: NVIDIA', 'Scholar: AMD', 'Scholar: Intel', 'Scholar: Google',
  'Scholar: Apple', 'Scholar: Microsoft', 'Scholar: Meta'
];

function venueHas(venues, ...needles) {
  const blob = venues.join(' ').toLowerCase();
  return needles.some(n => blob.includes(n.toLowerCase()));
}

const scholar_data = nodeNames.map((nodeName, idx) => {
  const wl = watchlist[idx];
  let resp = {};
  try { resp = $(nodeName).first().json || {}; } catch (e) { resp = {}; }
  const papers = Array.isArray(resp.data) ? resp.data : [];

  let total_citations = 0;
  let top_paper = null;
  for (const p of papers) {
    const cites = Number(p.citationCount || 0);
    total_citations += cites;
    if (!top_paper || cites > Number(top_paper.citationCount || 0)) {
      top_paper = { title: p.title, venue: p.venue, year: p.year, citationCount: cites };
    }
  }

  const paper_count = papers.length;
  const top_venues = [...new Set(papers.map(p => p.venue).filter(Boolean))];
  const avg_citations = paper_count ? Math.round((total_citations / paper_count) * 100) / 100 : 0;

  return {
    ticker: wl.ticker,
    company: wl.company,
    paper_count,
    top_venues,
    top_paper,
    total_citations,
    avg_citations,
    conference_presence: top_venues,
    has_neurips: venueHas(top_venues, 'neurips', 'neural information processing'),
    has_icml:    venueHas(top_venues, 'icml', 'international conference on machine learning'),
    has_cvpr:    venueHas(top_venues, 'cvpr', 'computer vision and pattern recognition'),
    has_iclr:    venueHas(top_venues, 'iclr', 'learning representations')
  };
});

return [{ json: { scholar_data, watchlist } }];

// Parse Layer B — Wikipedia MediaWiki revisions responses.
const watchlist = $('Fetch Watchlist').first().json.watchlist;
const nodeNames = [
  'Wikipedia: NVIDIA', 'Wikipedia: AMD', 'Wikipedia: Intel', 'Wikipedia: Google',
  'Wikipedia: Apple', 'Wikipedia: Microsoft', 'Wikipedia: Meta'
];

const wikipedia_data = nodeNames.map((nodeName, idx) => {
  const wl = watchlist[idx];
  let resp = {};
  try { resp = $(nodeName).first().json || {}; } catch (e) { resp = {}; }
  const pages = (resp.query && resp.query.pages) || {};
  const page = Object.values(pages)[0] || {};
  const revisions = Array.isArray(page.revisions) ? page.revisions : [];

  const unique_editors = [...new Set(revisions.map(r => r.user).filter(Boolean))].length;
  const edit_count_7d = revisions.length;
  const last_edit_timestamp = revisions.length ? revisions[0].timestamp : null;

  return {
    ticker: wl.ticker,
    company: wl.company,
    edit_count_7d,
    unique_editors,
    last_edit_timestamp,
    edit_velocity: Math.round((edit_count_7d / 7) * 100) / 100,
    is_spike: edit_count_7d > 10
  };
});

return [{ json: { wikipedia_data } }];

// Composite research_footprint_score (0-100) per company.
const scholar = $('Parse Scholar Data').first().json.scholar_data || [];
const wiki = $('Parse Wikipedia Data').first().json.wikipedia_data || [];

const wikiByTicker = {};
wiki.forEach(w => { wikiByTicker[w.ticker] = w; });

const companies = scholar.map(s => {
  const w = wikiByTicker[s.ticker] || {};

  // --- Scholar component (0-60) ---
  let scholar_component = 0;
  if (s.paper_count >= 8) scholar_component += 30;
  else if (s.paper_count >= 4) scholar_component += 20;
  else if (s.paper_count >= 1) scholar_component += 10;
  if (s.has_neurips) scholar_component += 8;
  if (s.has_icml)    scholar_component += 7;
  if (s.has_cvpr)    scholar_component += 5;
  if (s.has_iclr)    scholar_component += 5;
  if (s.avg_citations > 50) scholar_component += 5;
  scholar_component = Math.min(60, scholar_component);

  // --- Wikipedia component (0-40) ---
  const ec = w.edit_count_7d || 0;
  let wikipedia_component = 0;
  if (ec >= 20) wikipedia_component += 20;
  else if (ec >= 10) wikipedia_component += 15;
  else if (ec >= 5) wikipedia_component += 10;
  else wikipedia_component += 5; // baseline
  if ((w.unique_editors || 0) >= 10) wikipedia_component += 10;
  else if ((w.unique_editors || 0) >= 5) wikipedia_component += 5;
  if (w.is_spike) wikipedia_component += 10;
  wikipedia_component = Math.min(40, wikipedia_component);

  const research_footprint_score = Math.min(100, scholar_component + wikipedia_component);

  let footprint_tier = 'MINIMAL';
  if (research_footprint_score >= 75) footprint_tier = 'DOMINANT';
  else if (research_footprint_score >= 50) footprint_tier = 'STRONG';
  else if (research_footprint_score >= 25) footprint_tier = 'PRESENT';

  return {
    ticker: s.ticker,
    company: s.company,
    paper_count: s.paper_count,
    top_venues: s.top_venues,
    top_paper: s.top_paper,
    total_citations: s.total_citations,
    avg_citations: s.avg_citations,
    conference_presence: s.conference_presence,
    has_neurips: s.has_neurips,
    has_icml: s.has_icml,
    has_cvpr: s.has_cvpr,
    has_iclr: s.has_iclr,
    edit_count_7d: w.edit_count_7d || 0,
    unique_editors: w.unique_editors || 0,
    last_edit_timestamp: w.last_edit_timestamp || null,
    edit_velocity: w.edit_velocity || 0,
    is_spike: w.is_spike || false,
    scholar_component,
    wikipedia_component,
    research_footprint_score,
    footprint_tier
  };
});

return [{ json: { companies } }];

// Build a compact payload for the Groq analyst.
const companies = $json.companies || [];
const groq_input = {
  companies: companies.map(c => ({
    ticker: c.ticker,
    company: c.company,
    paper_count: c.paper_count,
    top_venues: c.top_venues,
    total_citations: c.total_citations,
    conference_presence: c.conference_presence,
    edit_count_7d: c.edit_count_7d,
    unique_editors: c.unique_editors,
    is_spike: c.is_spike,
    research_footprint_score: c.research_footprint_score,
    footprint_tier: c.footprint_tier
  }))
};

return [{ json: { companies, groq_input } }];

// Extract and parse the Groq JSON array; fall back to null on failure.
const prevData = $('Aggregate for Groq').first().json;

let content = '';
try { content = $json.choices[0].message.content || ''; } catch (e) { content = ''; }

let groq_classifications = null;
try {
  const cleaned = content
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  groq_classifications = JSON.parse(cleaned);
} catch (e) {
  groq_classifications = null;
}

return [{ json: { ...prevData, groq_classifications } }];

// Merge Groq classifications into company records.
// Emits ONE n8n item per company (flat DB columns) so the Supabase
// upsert writes 7 rows. Run-level summary is carried on every item.
const data = $json;
const companies = data.companies || [];
const classifications = Array.isArray(data.groq_classifications) ? data.groq_classifications : [];

const classByTicker = {};
classifications.forEach(c => { if (c && c.ticker) classByTicker[c.ticker] = c; });

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (ch) {
    const r = Math.random() * 16 | 0;
    const v = ch === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function isoWeek(d) {
  const date = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
  const dayNum = (date.getUTCDay() + 6) % 7;
  date.setUTCDate(date.getUTCDate() - dayNum + 3);
  const firstThursday = new Date(Date.UTC(date.getUTCFullYear(), 0, 4));
  const week = 1 + Math.round(
    ((date - firstThursday) / 86400000 - 3 + ((firstThursday.getUTCDay() + 6) % 7)) / 7
  );
  return date.getUTCFullYear() + '-W' + String(week).padStart(2, '0');
}

const now = new Date();
const run_timestamp = now.toISOString();
const run_week = isoWeek(now);
const agent_run_id = uuidv4();

const records = companies.map(c => {
  const g = classByTicker[c.ticker] || {};
  return {
    ticker: c.ticker,
    company: c.company,
    run_timestamp,
    run_week,
    agent_run_id,
    paper_count: c.paper_count,
    top_venues: c.top_venues,
    total_citations: c.total_citations,
    avg_citations: c.avg_citations,
    conference_presence: c.conference_presence,
    has_neurips: c.has_neurips,
    has_icml: c.has_icml,
    has_cvpr: c.has_cvpr,
    has_iclr: c.has_iclr,
    edit_count_7d: c.edit_count_7d,
    unique_editors: c.unique_editors,
    last_edit_timestamp: c.last_edit_timestamp,
    edit_velocity: c.edit_velocity,
    is_spike: c.is_spike,
    research_footprint_score: c.research_footprint_score,
    footprint_tier: c.footprint_tier,
    research_narrative: g.research_narrative || 'No narrative available (Groq parse fallback).',
    academic_signal: g.academic_signal || 'ABSENT',
    wikipedia_signal: g.wikipedia_signal || 'DORMANT',
    combined_insight: g.combined_insight || 'No insight available.',
    watch_flag: typeof g.watch_flag === 'boolean' ? g.watch_flag : false
  };
});

const dominant = records.filter(r => r.footprint_tier === 'DOMINANT');
const watchFlags = records.filter(r => r.watch_flag === true);
const wikiSpikes = records.filter(r => r.is_spike === true);

const summary = {
  runId: agent_run_id,
  runTimestamp: run_timestamp,
  runWeek: run_week,
  dominantCount: dominant.length,
  watchFlagCount: watchFlags.length,
  wikiSpikeCount: wikiSpikes.length
};

// One item per company record (flat columns) for the Supabase upsert.
return records.map(r => ({ json: { ...r, _summary: summary } }));

// Build the full markdown signal report.
// Reads the assembled records (one item per company) from Signal Assembler.
const items = $('Signal Assembler').all();
const records = items.map(i => i.json);
const summary = records.length ? records[0]._summary : {
  runId: 'unknown', runTimestamp: new Date().toISOString(), runWeek: 'unknown',
  dominantCount: 0, watchFlagCount: 0, wikiSpikeCount: 0
};

// Recompute scholar/wiki score components from raw fields for the breakdown table.
function components(r) {
  let s = 0;
  if (r.paper_count >= 8) s += 30;
  else if (r.paper_count >= 4) s += 20;
  else if (r.paper_count >= 1) s += 10;
  if (r.has_neurips) s += 8;
  if (r.has_icml) s += 7;
  if (r.has_cvpr) s += 5;
  if (r.has_iclr) s += 5;
  if (r.avg_citations > 50) s += 5;
  s = Math.min(60, s);

  let w = 0;
  const ec = r.edit_count_7d || 0;
  if (ec >= 20) w += 20;
  else if (ec >= 10) w += 15;
  else if (ec >= 5) w += 10;
  else w += 5;
  if ((r.unique_editors || 0) >= 10) w += 10;
  else if ((r.unique_editors || 0) >= 5) w += 5;
  if (r.is_spike) w += 10;
  w = Math.min(40, w);

  return { scholar: s, wiki: w };
}

const ranked = [...records].sort((a, b) => b.research_footprint_score - a.research_footprint_score);
const totalPapers = records.reduce((acc, r) => acc + (r.paper_count || 0), 0);
const totalCitations = records.reduce((acc, r) => acc + (r.total_citations || 0), 0);
const check = b => (b ? '✓' : '✗');

let md = '';
md += '# Research Footprint Monitor — Signal Report\n';
md += '**Run ID:** ' + summary.runId + '  \n';
md += '**Generated:** ' + summary.runTimestamp + '  \n';
md += '**Week:** ' + summary.runWeek + '\n\n';
md += '---\n\n';

md += '## Executive Summary\n\n';
md += '| Metric | Value |\n|---|---|\n';
md += '| Companies tracked | ' + records.length + ' |\n';
md += '| Dominant footprint | ' + summary.dominantCount + ' |\n';
md += '| Watch flags | ' + summary.watchFlagCount + ' |\n';
md += '| Wikipedia spikes | ' + summary.wikiSpikeCount + ' |\n';
md += '| Total papers found | ' + totalPapers + ' |\n';
md += '| Total citations | ' + totalCitations + ' |\n\n';
md += '---\n\n';

md += '## Research Footprint Rankings\n\n';
ranked.forEach((r, i) => {
  md += '### ' + (i + 1) + '. ' + r.company + ' (' + r.ticker + ') — Score: ' + r.research_footprint_score + '/100\n';
  md += '**Tier:** ' + r.footprint_tier + ' ';
  md += '| **Academic signal:** ' + r.academic_signal + ' ';
  md += '| **Wikipedia signal:** ' + r.wikipedia_signal + '  \n';
  md += '**Research narrative:** ' + r.research_narrative + '  \n';
  md += '**Combined insight:** ' + r.combined_insight + '  \n';
  md += '**Conference presence:** ' + ((r.conference_presence && r.conference_presence.length) ? r.conference_presence.join(', ') : 'none detected') + '  \n';
  md += '**Wikipedia edits (7d):** ' + r.edit_count_7d + ' (' + r.unique_editors + ' unique editors)  \n';
  md += '**Watch flag:** ' + (r.watch_flag ? '⚠ YES' : 'No') + '\n\n';
});
md += '---\n\n';

md += '## Watch Flags\n\n';
const flags = records.filter(r => r.watch_flag);
if (flags.length) {
  md += '| Ticker | Combined Insight |\n|---|---|\n';
  flags.forEach(r => { md += '| ' + r.ticker + ' | ' + r.combined_insight + ' |\n'; });
} else {
  md += '_No watch flags this run._\n';
}
md += '\n---\n\n';

md += '## Wikipedia Spikes\n\n';
const spikes = records.filter(r => r.is_spike);
if (spikes.length) {
  md += '| Ticker | Edits (7d) | Last Edit |\n|---|---|---|\n';
  spikes.forEach(r => { md += '| ' + r.ticker + ' | ' + r.edit_count_7d + ' | ' + (r.last_edit_timestamp || 'n/a') + ' |\n'; });
} else {
  md += '_No Wikipedia spikes (>10 edits/week) this run._\n';
}
md += '\n_Note: Wikipedia spikes often precede news cycles by 24-72 hrs._\n\n';
md += '---\n\n';

md += '## Conference Presence Matrix\n\n';
md += '| Company | NeurIPS | ICML | CVPR | ICLR | Papers | Citations |\n|---|---|---|---|---|---|---|\n';
ranked.forEach(r => {
  md += '| ' + r.company + ' | ' + check(r.has_neurips) + ' | ' + check(r.has_icml) + ' | ' + check(r.has_cvpr) + ' | ' + check(r.has_iclr) + ' | ' + r.paper_count + ' | ' + r.total_citations + ' |\n';
});
md += '\n---\n\n';

md += '## Score Breakdown\n\n';
md += '| Company | Scholar Score (/60) | Wikipedia Score (/40) | Total (/100) | Tier |\n|---|---|---|---|---|\n';
ranked.forEach(r => {
  const c = components(r);
  md += '| ' + r.company + ' | ' + c.scholar + ' | ' + c.wiki + ' | ' + r.research_footprint_score + ' | ' + r.footprint_tier + ' |\n';
});
md += '\n---\n\n';

md += '## Known Limitations\n';
md += '- Semantic Scholar query matches on company name in paper metadata — may include papers not from the company\'s official research arm.\n';
md += '- Wikipedia edit count covers all edit types including minor bot edits — not all edits represent human knowledge-building activity.\n';
md += '- Conference presence based on venue field in Semantic Scholar, which is inconsistently populated.\n';
md += '- First run has no week-over-week comparison.\n\n';
md += '---\n\n';

md += '*Mycroft — Research Footprint Monitor | Agent 5*  \n';
md += '*Stack: n8n + Semantic Scholar API + Wikipedia MediaWiki API*  \n';
md += '*+ Groq (llama-3.3-70b) + Supabase*\n';

return [{ json: {
  report: md,
  run_id: summary.runId,
  report_markdown: md,
  companies_tracked: records.length,
  dominant_count: summary.dominantCount,
  watch_flag_count: summary.watchFlagCount,
  wiki_spike_count: summary.wikiSpikeCount
}}];
